  <script>
    // Xử lý dữ liệu khi trang được tải xong
    document.addEventListener('DOMContentLoaded', function() {
      // Đầu tiên, tạo hiệu ứng mây trôi
      createParticles();

      // Thiết lập chức năng chuyển tab
      document.querySelectorAll('.tab-button').forEach(button => {
        button.addEventListener('click', function() {
          document.querySelectorAll('.tab-button').forEach(btn => btn.classList.remove('active'));
          this.classList.add('active');

          const targetId = this.dataset.target;
          document.querySelectorAll('.content').forEach(content => {
            content.style.display = 'none';
          });
          document.getElementById(targetId).style.display = 'block';
        });
      });

      // Xử lý liên kết hình ảnh
      const mainContent = document.querySelector('#main-content');
      if (mainContent) {
        mainContent.innerHTML = processImageLinks(mainContent.innerHTML);
      }

      // Xử lý văn bản trích dẫn
      if (mainContent) {
        mainContent.innerHTML = mainContent.innerHTML.replace(
          /「([^」]+)」|"([^"]+)"/g,
          match => `<span class="quote-text">${match}</span>`
        );
      }

      // Trích xuất dữ liệu Tiên Duyên
      const rinContent = document.querySelector('.raw-data').innerHTML.match(/<rin-content>([\s\S]*?)<\/rin-content>/);
      if (rinContent && rinContent[1]) {
        setElementContent('player-level', extractValue(rinContent[1], /player_level: (.*?)$/m));
        setElementContent('player-status', extractValue(rinContent[1], /player_status: (.*?)$/m));
        setElementContent('player-items', extractValue(rinContent[1], /player_items: (.*?)$/m));
        setElementContent('player-thought', extractValue(rinContent[1], /player_thought: (.*?)$/m));
        setElementContent('player-affection', extractValue(rinContent[1], /player_affection: (.*?)$/m));

        // Xử lý thanh tiến độ Linh Duyên
        const progress = extractValue(rinContent[1], /player_affection_progress: (.*?)$/m);
        if (progress) {
          const progressParts = progress.split('/');
          if (progressParts.length === 2) {
            const progressPercent = (parseInt(progressParts[0]) / parseInt(progressParts[1])) * 100;
            setProgressBar('player-affection-progress-bar', progressPercent.toString());
          }
        }
      }

      // Trích xuất dữ liệu túi đồ
      const inventoryContent = document.getElementById('inventory-raw').textContent;

      // Thông tin sự kiện quan trọng
      setElementContent('time-info', extractValue(inventoryContent, /time_info: (.*?)$/m));
      setElementContent('place-info', extractValue(inventoryContent, /place_info: (.*?)$/m));
      setElementContent('location-info', extractValue(inventoryContent, /location_info: (.*?)$/m));
      setElementContent('current-event', extractValue(inventoryContent, /current_event: (.*?)$/m));
      setElementContent('recent-event', extractValue(inventoryContent, /recent_event: (.*?)$/m));

      // Trích xuất dữ liệu nhiệm vụ
      const questsContent = document.getElementById('quests-raw').textContent;

      // Thiết lập nội dung nhiệm vụ
      setElementContent('quest-main', extractValue(questsContent, /quest_main: (.*?)$/m));
      setElementContent('quest-side', extractValue(questsContent, /quest_side: (.*?)$/m));
      setElementContent('quest-longterm', extractValue(questsContent, /quest_longterm: (.*?)$/m));

      // Thiết lập thanh tiến độ nhiệm vụ
      setProgressBar('quest-main-progress-bar', extractValue(questsContent, /quest_main_progress: (.*?)$/m));
      setProgressBar('quest-side-progress-bar', extractValue(questsContent, /quest_side_progress: (.*?)$/m));
      setProgressBar('quest-longterm-progress-bar', extractValue(questsContent, /quest_longterm_progress: (.*?)$/m));

      // Tự động tạo thanh trạng thái của các đạo hữu
      generateStatusSections();
    });

    // Hàm tạo mây tiên trôi nổi
    function createParticles() {
      const container = document.querySelector('.floating-particles');
      const particleCount = 15;

      for (let i = 0; i < particleCount; i++) {
        const particle = document.createElement('div');
        particle.classList.add('particle');

        // Vị trí ngẫu nhiên
        const x = Math.floor(Math.random() * 100);
        const y = Math.floor(Math.random() * 100);
        particle.style.left = `${x}%`;
        particle.style.top = `${y}%`;

        // Kích thước ngẫu nhiên
        const size = 20 + Math.random() * 40;
        particle.style.width = `${size}px`;
        particle.style.height = `${size * 0.6}px`;

        // Độ trễ và thời gian hoạt ảnh ngẫu nhiên
        const delay = Math.random() * 20;
        const duration = 40 + Math.random() * 60;
        particle.style.animation = `float ${duration}s ${delay}s infinite linear`;

        // Góc xoay ngẫu nhiên
        const rotate = Math.random() * 360;
        particle.style.transform = `rotate(${rotate}deg)`;

        // Độ trong suốt ngẫu nhiên
        const opacity = 0.1 + Math.random() * 0.3;
        particle.style.opacity = opacity;

        container.appendChild(particle);
      }
    }

    // Hàm trích xuất giá trị từ một chuỗi dựa trên mẫu
    function extractValue(content, pattern) {
      const match = content.match(pattern);
      return match ? match[1].trim() : "Không rõ";
    }

    // Hàm thiết lập nội dung và thêm lớp CSS cho phần tử
    function setElementContent(id, content, isItem = false) {
      const element = document.getElementById(id);
      if (element) {
        element.textContent = content;
        if (isItem) {
          if (content === '是' || content === '拥有') {
            element.classList.add('has-item');
          } else if (content === '否' || content === '未拥有') {
            element.classList.add('no-item');
          }
        }
      }
    }

    // Hàm thiết lập thanh tiến độ
    function setProgressBar(id, progress) {
      const progressBar = document.getElementById(id);
      if (progressBar) {
        const value = parseInt(progress) || 0;
        progressBar.style.width = `${value}%`;
      }
    }

    // Hàm xử lý liên kết hình ảnh để hiển thị
    function processImageLinks(content) {
      const imageRegex = /(?:https:\/\/files\.catbox\.moe\/)?([a-zA-Z0-9]{6})\.jpg/g;
      return content.replace(imageRegex, (match, imageId) => {
        return `<img src="https://files.catbox.moe/${imageId}.jpg" class="character-avatar">`;
      });
    }

    // Hàm tự động tạo khu vực trạng thái cho các đạo hữu
    function generateStatusSections() {
      const statusContainer = document.getElementById('status-content');
      statusContainer.innerHTML = '';
      const statusContent = document.getElementById('statusbar-raw').textContent;

      // Biểu thức chính quy mới để lấy cả ID nhân vật và tên tùy chỉnh
      const characterRegex = /([a-z])_name: (.*?)$[\s\S]*?([a-z])_level: (.*?)$[\s\S]*?([a-z])_affection: (.*?)$[\s\S]*?([a-z])_status: (.*?)$[\s\S]*?([a-z])_impression: (.*?)$/gm;

      const matches = [...statusContent.matchAll(characterRegex)];

      // Giới hạn hiển thị tối đa ba nhân vật
      const charactersToShow = matches.slice(0, 3);

      charactersToShow.forEach(match => {
        const charId = match[1];
        const charName = match[2].trim(); // Lấy tên tùy chỉnh

        // Tạo khu vực trạng thái
        const section = document.createElement('div');
        section.className = 'status-section';

        // Lấy thông tin avatar
        const avatarValue = extractValue(statusContent, new RegExp(`${charId}_avatar: (.*?)$`, 'm'));

        // Tạo avatar (kiểm tra xem có phải URL đầy đủ không)
        const avatar = document.createElement('div');
        avatar.className = 'character-avatar';

        // Kiểm tra xem đã là một liên kết URL hoàn chỉnh chưa
        if (avatarValue.startsWith('http://') || avatarValue.startsWith('https://')) {
          // Sử dụng trực tiếp liên kết đầy đủ
          avatar.style.backgroundImage = `url('${avatarValue}')`;
        } else {
          // Sử dụng định dạng liên kết mặc định
          avatar.style.backgroundImage = `url('https://files.catbox.moe/${avatarValue}.jpg')`;
        }

        // Tạo khu vực thông tin
        const info = document.createElement('div');
        info.className = 'character-info';
        info.innerHTML = `
          【${charName}】<br>
          Động phủ hiện tại: <span id="${charId}-level">${extractValue(statusContent, new RegExp(`${charId}_level: (.*?)$`, 'm'))}</span><br>
          Linh duyên: <span id="${charId}-affection">${extractValue(statusContent, new RegExp(`${charId}_affection: (.*?)$`, 'm'))}</span><br>
          Trạng thái tu vi: <span id="${charId}-status">${extractValue(statusContent, new RegExp(`${charId}_status: (.*?)$`, 'm'))}</span><br>
          Ấn tượng: <span id="${charId}-impression">${extractValue(statusContent, new RegExp(`${charId}_impression: (.*?)$`, 'm'))}</span>
        `;

        section.appendChild(avatar);
        section.appendChild(info);
        statusContainer.appendChild(section);
      });

      // Nếu không có đạo hữu nào, hiển thị thông báo
      if (charactersToShow.length === 0) {
        const emptyMessage = document.createElement('div');
        emptyMessage.className = 'status-section';
        emptyMessage.innerHTML = '<p style="text-align: center; color: #7d8db5; font-style: italic;">Chưa kết duyên cùng đạo hữu nào, tiên lộ tịch mịch.</p>';
        statusContainer.appendChild(emptyMessage);
      }
    }
  </script>
